import React, { useEffect, useRef } from 'react';

function DottedSphere({ size = 600, className = '' }) {
  const canvasRef = useRef(null);
  const animationRef = useRef(null);
  const angleRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;

    canvas.width = size * dpr;
    canvas.height = size * dpr;
    ctx.scale(dpr, dpr);

    const centerX = size / 2;
    const centerY = size / 2;
    const radius = size / 2.8;

    function draw() {
      ctx.clearRect(0, 0, size, size);

      // Background glow
      const glow = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, radius * 1.5);
      glow.addColorStop(0, 'rgba(139, 92, 246, 0.15)');
      glow.addColorStop(0.4, 'rgba(124, 58, 237, 0.08)');
      glow.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = glow;
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius * 1.5, 0, Math.PI * 2);
      ctx.fill();

      const dots = [];
      const rotationY = angleRef.current;

      // Horizontal rings (latitude lines)
      for (let lat = -9; lat <= 9; lat++) {
        const theta = (lat / 9) * (Math.PI / 2);
        const ringRadius = Math.cos(theta) * radius;
        const y = Math.sin(theta) * radius;
        const numDots = Math.max(8, Math.floor(40 * Math.cos(theta)));

        for (let i = 0; i < numDots; i++) {
          const phi = (i / numDots) * Math.PI * 2 + rotationY;
          const x = Math.cos(phi) * ringRadius;
          const z = Math.sin(phi) * ringRadius;

          dots.push({
            x: centerX + x,
            y: centerY - y,
            z: z,
            depth: (z + radius) / (2 * radius)
          });
        }
      }

      // Vertical rings (longitude lines) 
      for (let lon = 0; lon < 12; lon++) {
        const phi = (lon / 12) * Math.PI + rotationY;

        for (let lat = 0; lat <= 20; lat++) {
          const theta = (lat / 20) * Math.PI;
          const x = Math.sin(theta) * Math.cos(phi) * radius;
          const y = Math.cos(theta) * radius;
          const z = Math.sin(theta) * Math.sin(phi) * radius;

          dots.push({
            x: centerX + x,
            y: centerY - y,
            z: z,
            depth: (z + radius) / (2 * radius)
          });
        }
      }

      // Sort back to front
      dots.sort((a, b) => a.z - b.z);

      // Draw dots
      dots.forEach(dot => {
        const alpha = 0.1 + dot.depth * 0.7;
        const dotSize = 1 + dot.depth * 2.5;

        // Glow for front dots
        if (dot.depth > 0.5) {
          ctx.beginPath();
          ctx.arc(dot.x, dot.y, dotSize * 2.5, 0, Math.PI * 2);
          ctx.fillStyle = `rgba(167, 139, 250, ${alpha * 0.15})`;
          ctx.fill();
        }

        ctx.beginPath();
        ctx.arc(dot.x, dot.y, dotSize, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(167, 139, 250, ${alpha})`;
        ctx.fill();
      });

      angleRef.current += 0.002;
      animationRef.current = requestAnimationFrame(draw);
    }

    draw();

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [size]);

  return (
    <div className={`absolute pointer-events-none ${className}`}>
      <canvas 
        ref={canvasRef}
        style={{ width: size, height: size }}
      />
    </div>
  );
}

export default DottedSphere;
